def _insert_aux(self, node, x):
    """Recursive insert helper. Returns (new_node, inserted_flag)."""
    if isinstance(node, Nodoe):
        return Nodoi(Nodoe(0), x, 1, Nodoe(0)), True
    if x < node.info:
        new_child, inserted = self._insert_aux(node.izq, x)
        node.izq = new_child
        if inserted:
            node.contador += 1
        return node, inserted
    if x > node.info:
        new_child, inserted = self._insert_aux(node.der, x)
        node.der = new_child
        if inserted:
            node.contador += 1
        return node, inserted
    # x == node.info: duplicate key, do nothing
    return node, False

def insert(self, x):
    self.raiz, _ = self._insert_aux(self.raiz, x)

def _search_aux(self, node, x):
    """Recursive search helper."""
    if isinstance(node, Nodoe):
        return None
    if x == node.info:
        return node
    if x < node.info:
        return self._search_aux(node.izq, x)
    return self._search_aux(node.der, x)

def search(self, x):
    return self._search_aux(self.raiz, x)

def _find_aux(self, node, k):
    """Recursive find helper."""
    if isinstance(node, Nodoe):
        return None
    left_counter = node.izq.contador if isinstance(node.izq, Nodoi) else 0
    if left_counter >= k:
        return self._find_aux(node.izq, k)
    if left_counter + 1 == k:
        return node
    return self._find_aux(node.der, k - left_counter - 1)

def find(self, k):
    return self._find_aux(self.raiz, k)

